advanced_example:
## 💻 Level 3 — Real Project Example
```javascript
function parseAPIResponse(raw_json) {
  try {
    const payload = JSON.parse(raw_json);
    if (!payload.success) return "Request Failed";
    return payload.data;
  } catch (err) {
    return "Malformed JSON payload";
  }
}
```
